from langsmith import traceable
import anthropic

client = anthropic.Anthropic()


@traceable(run_type="chain", name="agent_turn", tags=["production"])
def run_agent(user_message: str) -> str:
    context = retrieve_context(user_message)
    return call_model(user_message, context)


@traceable(run_type="retrieval", name="retrieve_context")
def retrieve_context(query: str) -> list[str]:
    # child run: run_type=retrieval
    return [f"doc about {query}"]


@traceable(run_type="llm", name="call_model")
def call_model(message: str, context: list[str]) -> str:
    # child run: run_type=llm
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        messages=[{"role": "user", "content": f"{context}\n\n{message}"}],
    )
    return resp.content[0].text


result = run_agent("How do I reset my password?")
# → one chain run with two child runs in the LangSmith UI
